// 菜品数据 - 虚构品牌「膳野 SHANYĚ」
const CATEGORIES = [
  { id: 'signature', name: '招牌', sub: 'Signature' },
  { id: 'rice',      name: '饭食', sub: 'Rice' },
  { id: 'noodle',    name: '面食', sub: 'Noodle' },
  { id: 'side',      name: '小菜', sub: 'Side' },
  { id: 'soup',      name: '汤品', sub: 'Soup' },
  { id: 'drink',     name: '饮品', sub: 'Drink' },
];

const DISHES = [
  // 招牌
  { id: 'd01', cat:'signature', name:'古法卤味三拼', en:'Braised Trio',     price: 58, desc:'老卤慢煨，牛腱 · 豆干 · 鸡翅',    tag:'招牌', sold: 328, spicy:1,
    specs:[{k:'份量',opts:[{n:'小份',p:0},{n:'大份',p:18}]}], addons:[{n:'加卤蛋',p:4},{n:'加豆干',p:6}] },
  { id: 'd02', cat:'signature', name:'山野菌菇煲仔饭', en:'Mushroom Claypot', price: 48, desc:'五种菌菇 · 米饭焦香',            tag:'热销', sold: 612, spicy:0,
    specs:[{k:'米饭',opts:[{n:'丝苗米',p:0},{n:'糙米',p:2}]}], addons:[{n:'加蛋',p:3},{n:'双倍菌菇',p:8}] },
  { id: 'd03', cat:'signature', name:'黑松露和牛饭', en:'Truffle Wagyu Rice', price: 98, desc:'A4 和牛 · 黑松露酱 · 温泉蛋',     tag:'主厨', sold: 186, spicy:0,
    specs:[{k:'熟度',opts:[{n:'五分',p:0},{n:'七分',p:0}]}], addons:[{n:'加温泉蛋',p:5}] },

  // 饭
  { id: 'd11', cat:'rice', name:'鳗鱼照烧饭',   en:'Unagi Rice',    price: 68, desc:'活鳗现烤 · 照烧酱汁',    sold: 241, spicy:0,
    specs:[{k:'米饭',opts:[{n:'常规',p:0},{n:'加饭',p:4}]}], addons:[{n:'加鳗鱼',p:18}] },
  { id: 'd12', cat:'rice', name:'藤椒鸡腿饭',   en:'Sichuan Chicken', price: 42, desc:'藤椒清香 · 去骨鸡腿',    sold: 489, spicy:2,
    specs:[{k:'辣度',opts:[{n:'微辣',p:0},{n:'中辣',p:0},{n:'重辣',p:0}]}], addons:[{n:'加鸡腿',p:10}] },
  { id: 'd13', cat:'rice', name:'梅干菜东坡饭', en:'Pork Belly Rice', price: 45, desc:'慢炖四小时 · 肥而不腻',  sold: 302, spicy:0, specs:[], addons:[{n:'加蛋',p:3}] },

  // 面
  { id: 'd21', cat:'noodle', name:'招牌牛腩面',  en:'Beef Brisket',   price: 46, desc:'清炖牛腩 · 手工碱水面',   sold: 521, spicy:0,
    specs:[{k:'面条',opts:[{n:'碱水面',p:0},{n:'刀削面',p:0},{n:'米粉',p:0}]}], addons:[{n:'加牛腩',p:12}] },
  { id: 'd22', cat:'noodle', name:'山椒酸汤面', en:'Sour Pepper',    price: 38, desc:'野山椒 · 开胃酸辣',       sold: 156, spicy:2, specs:[], addons:[] },

  // 小菜
  { id: 'd31', cat:'side', name:'凉拌木耳',    en:'Wood Ear',     price: 18, desc:'东北黑木耳 · 老陈醋',      sold: 88,  spicy:1, specs:[], addons:[] },
  { id: 'd32', cat:'side', name:'爽口莴笋',    en:'Crisp Lettuce', price: 16, desc:'现刨莴笋 · 花椒油',        sold: 72,  spicy:0, specs:[], addons:[] },
  { id: 'd33', cat:'side', name:'泡椒凤爪',    en:'Chicken Feet',  price: 22, desc:'野山椒泡制 · 弹牙',        sold: 134, spicy:2, specs:[], addons:[] },

  // 汤
  { id: 'd41', cat:'soup', name:'老火例汤',    en:'Daily Soup',    price: 12, desc:'每日熬煮 · 依季节更换',    sold: 201, spicy:0, specs:[], addons:[] },
  { id: 'd42', cat:'soup', name:'菌菇鸡汤',    en:'Chicken Soup',  price: 28, desc:'走地鸡 · 四菌炖煮',        sold: 167, spicy:0, specs:[], addons:[] },

  // 饮
  { id: 'd51', cat:'drink', name:'桂花乌龙',   en:'Osmanthus Oolong', price: 15, desc:'新茶现泡 · 桂花蜜',     sold: 342, spicy:0,
    specs:[{k:'温度',opts:[{n:'冰',p:0},{n:'常温',p:0},{n:'热',p:0}]},{k:'糖度',opts:[{n:'无糖',p:0},{n:'三分',p:0},{n:'五分',p:0}]}], addons:[] },
  { id: 'd52', cat:'drink', name:'柠檬苏打',   en:'Lemon Soda',      price: 12, desc:'鲜榨柠檬 · 苏打水',      sold: 211, spicy:0,
    specs:[{k:'冰量',opts:[{n:'正常冰',p:0},{n:'少冰',p:0},{n:'去冰',p:0}]}], addons:[] },
  { id: 'd53', cat:'drink', name:'酸梅汤',     en:'Plum Juice',       price: 10, desc:'古法熬制 · 解腻',       sold: 178, spicy:0, specs:[], addons:[] },
];

// 以视觉化的方式表达菜品：每道菜用两种色带 + 符号标签（无真实图片）
const DISH_VISUALS = {
  d01:{a:'#3b2a16',b:'#6b4a24',g:'卤'}, d02:{a:'#2c2416',b:'#5c4a2a',g:'煲'},
  d03:{a:'#1f1610',b:'#3a2418',g:'牛'}, d11:{a:'#3a2612',b:'#7a4e24',g:'鳗'},
  d12:{a:'#2e2a14',b:'#6a5a22',g:'藤'}, d13:{a:'#24180f',b:'#4a2e18',g:'梅'},
  d21:{a:'#2a1f14',b:'#5a4428',g:'牛'}, d22:{a:'#2e1a1a',b:'#6a2a2a',g:'酸'},
  d31:{a:'#1a1611',b:'#2e261c',g:'木'}, d32:{a:'#1e2218',b:'#34402a',g:'莴'},
  d33:{a:'#2e1815',b:'#6a2018',g:'椒'}, d41:{a:'#241a12',b:'#42321e',g:'汤'},
  d42:{a:'#2a2416',b:'#54462a',g:'菌'}, d51:{a:'#2a2014',b:'#5a4222',g:'茶'},
  d52:{a:'#1c2024',b:'#324050',g:'苏'}, d53:{a:'#2a1216',b:'#50181e',g:'梅'},
};

window.CATEGORIES = CATEGORIES;
window.DISHES = DISHES;
window.DISH_VISUALS = DISH_VISUALS;

// 极简线性图标 — 金色描边
const IconBase = ({ children, size=20, stroke='currentColor', sw=1.4 }) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none"
       stroke={stroke} strokeWidth={sw} strokeLinecap="round" strokeLinejoin="round">
    {children}
  </svg>
);

const IconChevron    = (p)=> <IconBase {...p}><path d="M9 18l6-6-6-6"/></IconBase>;
const IconBack       = (p)=> <IconBase {...p}><path d="M15 18l-6-6 6-6"/></IconBase>;
const IconClose      = (p)=> <IconBase {...p}><path d="M6 6l12 12M18 6L6 18"/></IconBase>;
const IconCart       = (p)=> <IconBase {...p}>
  <path d="M4 5h2l2.2 10.3a2 2 0 0 0 2 1.6h7.1a2 2 0 0 0 2-1.5L21 8H7"/>
  <circle cx="10" cy="20" r="1.2"/><circle cx="18" cy="20" r="1.2"/>
</IconBase>;
const IconPlus       = (p)=> <IconBase {...p}><path d="M12 5v14M5 12h14"/></IconBase>;
const IconMinus      = (p)=> <IconBase {...p}><path d="M5 12h14"/></IconBase>;
const IconCheck      = (p)=> <IconBase {...p}><path d="M5 12l4 4L19 7"/></IconBase>;
const IconTrash      = (p)=> <IconBase {...p}>
  <path d="M4 7h16M9 7V5a2 2 0 0 1 2-2h2a2 2 0 0 1 2 2v2M6 7l1 13a2 2 0 0 0 2 2h6a2 2 0 0 0 2-2l1-13"/>
</IconBase>;
const IconTable      = (p)=> <IconBase {...p}>
  <path d="M3 9h18M5 9v10M19 9v10M9 19v-4M15 19v-4"/>
</IconBase>;
const IconScan       = (p)=> <IconBase {...p}>
  <path d="M4 8V5a1 1 0 0 1 1-1h3M20 8V5a1 1 0 0 0-1-1h-3M4 16v3a1 1 0 0 0 1 1h3M20 16v3a1 1 0 0 1-1 1h-3M3 12h18"/>
</IconBase>;
const IconFlame      = (p)=> <IconBase {...p}><path d="M12 3s4 4 4 8a4 4 0 0 1-8 0c0-1.5.7-2.7 1.5-3.5C9 9 10 8 10 6c1 1 2 1.5 2 3V3z"/></IconBase>;
const IconClock      = (p)=> <IconBase {...p}><circle cx="12" cy="12" r="9"/><path d="M12 7v5l3 2"/></IconBase>;
const IconTicket     = (p)=> <IconBase {...p}>
  <path d="M4 9V6a1 1 0 0 1 1-1h14a1 1 0 0 1 1 1v3a2 2 0 0 0 0 4v3a1 1 0 0 1-1 1H5a1 1 0 0 1-1-1v-3a2 2 0 0 0 0-4z"/>
  <path d="M10 5v14" strokeDasharray="2 2"/>
</IconBase>;
const IconUser       = (p)=> <IconBase {...p}><circle cx="12" cy="8" r="4"/><path d="M4 21c0-4 4-6 8-6s8 2 8 6"/></IconBase>;
const IconNote       = (p)=> <IconBase {...p}><path d="M4 5h16v14H4zM8 9h8M8 13h8M8 17h5"/></IconBase>;
const IconSearch     = (p)=> <IconBase {...p}><circle cx="11" cy="11" r="6"/><path d="M20 20l-4-4"/></IconBase>;

// 金色装饰花纹 — 极简菱形
const Ornament = ({ w=80, color='var(--gold)' }) => (
  <svg width={w} height="10" viewBox="0 0 80 10" fill="none">
    <path d="M0 5h30" stroke={color} strokeWidth="0.6"/>
    <path d="M50 5h30" stroke={color} strokeWidth="0.6"/>
    <path d="M40 1l4 4-4 4-4-4z" stroke={color} strokeWidth="0.8" fill="none"/>
  </svg>
);

Object.assign(window, {
  IconChevron, IconBack, IconClose, IconCart, IconPlus, IconMinus, IconCheck,
  IconTrash, IconTable, IconScan, IconFlame, IconClock, IconTicket, IconUser,
  IconNote, IconSearch, Ornament,
});

// 通用组件 + 视觉原件

// 菜品视觉占位 — 两段色带 + 纹理 + 金色字符
const DishVisual = ({ id, size=96, label }) => {
  const v = window.DISH_VISUALS[id] || {a:'#2a241a', b:'#4a3a20', g:'膳'};
  const gradId = `g-${id}`;
  return (
    <svg width={size} height={size} viewBox="0 0 100 100" style={{display:'block',borderRadius:6}}>
      <defs>
        <linearGradient id={gradId} x1="0" y1="0" x2="1" y2="1">
          <stop offset="0%" stopColor={v.a}/>
          <stop offset="100%" stopColor={v.b}/>
        </linearGradient>
        <pattern id={`p-${id}`} width="6" height="6" patternUnits="userSpaceOnUse" patternTransform="rotate(30)">
          <line x1="0" y1="0" x2="0" y2="6" stroke="rgba(201,169,106,0.06)" strokeWidth="1"/>
        </pattern>
      </defs>
      <rect width="100" height="100" fill={`url(#${gradId})`}/>
      <rect width="100" height="100" fill={`url(#p-${id})`}/>
      {/* 内圈边框 */}
      <rect x="4" y="4" width="92" height="92" fill="none" stroke="rgba(201,169,106,0.18)" strokeWidth="0.6"/>
      {/* 中心圆 */}
      <circle cx="50" cy="50" r="18" fill="none" stroke="rgba(201,169,106,0.35)" strokeWidth="0.6"/>
      <text x="50" y="56" textAnchor="middle" fontSize="18"
            fontFamily='"Noto Serif SC", serif' fontWeight="500"
            fill="#C9A96A" style={{letterSpacing:'0.02em'}}>{v.g}</text>
      {label && (
        <text x="50" y="94" textAnchor="middle" fontSize="4"
              fontFamily='"JetBrains Mono", monospace'
              fill="rgba(201,169,106,0.35)" style={{letterSpacing:'0.12em'}}>{label}</text>
      )}
    </svg>
  );
};

// 辣度
const Spicy = ({ n=0 }) => {
  if (!n) return null;
  return (
    <span style={{display:'inline-flex',gap:2,marginLeft:6,verticalAlign:'middle'}}>
      {Array.from({length:n}).map((_,i)=>(
        <svg key={i} width="9" height="9" viewBox="0 0 24 24" fill="#C86B5A">
          <path d="M12 3s4 4 4 8a4 4 0 0 1-8 0c0-1.5.7-2.7 1.5-3.5C9 9 10 8 10 6c1 1 2 1.5 2 3V3z"/>
        </svg>
      ))}
    </span>
  );
};

// 步进器
const Stepper = ({ qty, onInc, onDec, gold=true }) => {
  const c = gold ? 'var(--gold)' : 'var(--ink)';
  return (
    <div style={{display:'inline-flex',alignItems:'center',gap:10}}>
      {qty>0 && (
        <button onClick={onDec} style={{
          width:26,height:26,borderRadius:'50%',border:`1px solid ${c}`,color:c,
          display:'flex',alignItems:'center',justifyContent:'center'}}>
          <IconMinus size={14} stroke={c} sw={1.6}/>
        </button>
      )}
      {qty>0 && (
        <span style={{minWidth:16,textAlign:'center',fontFamily:'var(--mono)',fontSize:15,color:'var(--ink)'}}>{qty}</span>
      )}
      <button onClick={onInc} style={{
        width:26,height:26,borderRadius:'50%',background:c,color:'#0E0F0C',
        display:'flex',alignItems:'center',justifyContent:'center'}}>
        <IconPlus size={14} stroke={'#0E0F0C'} sw={2}/>
      </button>
    </div>
  );
};

// 价格显示 — 带¥符号与货币字形
const Price = ({ value, size=16, color='var(--gold)' }) => (
  <span style={{color,fontFamily:'var(--mono)',fontSize:size,fontWeight:500,letterSpacing:'0.01em'}}>
    <span style={{fontSize:size*0.72,marginRight:2,opacity:0.85}}>¥</span>
    {value}
  </span>
);

// 顶部状态栏（仿 iOS）
const StatusBar = ({ dark=true }) => {
  const color = dark ? 'var(--ink)' : '#0E0F0C';
  return (
    <div style={{
      height:44, display:'flex', alignItems:'center', justifyContent:'space-between',
      padding:'0 22px', fontFamily:'var(--sans)', fontSize:15, fontWeight:600,
      color, letterSpacing:'0.02em',
    }}>
      <span>9:41</span>
      <span style={{display:'flex',alignItems:'center',gap:5}}>
        {/* 信号 */}
        <svg width="16" height="10" viewBox="0 0 16 10" fill={color}>
          <rect x="0" y="6" width="3" height="4" rx="0.5"/>
          <rect x="4" y="4" width="3" height="6" rx="0.5"/>
          <rect x="8" y="2" width="3" height="8" rx="0.5"/>
          <rect x="12" y="0" width="3" height="10" rx="0.5"/>
        </svg>
        {/* wifi */}
        <svg width="14" height="10" viewBox="0 0 14 10" fill="none" stroke={color} strokeWidth="1.2">
          <path d="M1 3.5a9 9 0 0 1 12 0M3 5.8a6 6 0 0 1 8 0M5 8a3 3 0 0 1 4 0"/>
        </svg>
        {/* 电量 */}
        <svg width="24" height="11" viewBox="0 0 24 11" fill="none">
          <rect x="0.5" y="0.5" width="20" height="10" rx="2" stroke={color} fill="none"/>
          <rect x="21.5" y="3.5" width="1.5" height="4" rx="0.5" fill={color}/>
          <rect x="2" y="2" width="16" height="7" rx="1" fill={color}/>
        </svg>
      </span>
    </div>
  );
};

// Home 指示条
const HomeBar = ({ light=true }) => (
  <div style={{height:24,display:'flex',alignItems:'flex-end',justifyContent:'center',paddingBottom:8}}>
    <div style={{width:134,height:5,borderRadius:3,background: light?'var(--ink)':'#000',opacity:0.9}}/>
  </div>
);

// 品牌字标
const BrandMark = ({ size=18, dim=false }) => (
  <span style={{
    fontFamily:'var(--serif)', fontWeight:500, fontSize:size,
    letterSpacing:'0.3em', color: dim?'var(--ink-2)':'var(--ink)',
  }}>
    膳 野
    <span style={{
      fontFamily:'var(--sans)', fontSize:size*0.5, letterSpacing:'0.2em',
      marginLeft:8, color:'var(--gold)', verticalAlign:'middle',
    }}>SHANYĚ</span>
  </span>
);

// 标签/徽章
const Tag = ({ children, color='var(--gold)' }) => (
  <span style={{
    display:'inline-block', padding:'2px 7px', fontSize:10, letterSpacing:'0.12em',
    color, border:`0.5px solid ${color}`, borderRadius:2,
    fontFamily:'var(--sans)', fontWeight:500,
  }}>{children}</span>
);

// 移动设备外框：375 × 812，无 bezel，仅 viewport
const Phone = ({ children, dark=true, noStatus=false, noHome=false }) => (
  <div style={{
    width:390, height:844, borderRadius:46,
    background:'var(--bg)',
    boxShadow:'0 40px 80px rgba(0,0,0,0.6), 0 0 0 1px rgba(201,169,106,0.06)',
    overflow:'hidden', position:'relative', display:'flex', flexDirection:'column',
  }}>
    {!noStatus && <StatusBar dark={dark}/>}
    <div style={{flex:1,overflow:'hidden',position:'relative'}}>{children}</div>
    {!noHome && <HomeBar light={dark}/>}
  </div>
);

Object.assign(window, { DishVisual, Spicy, Stepper, Price, StatusBar, HomeBar, BrandMark, Tag, Phone });

// 扫码进入页 / 桌位欢迎
const ScreenLanding = ({ onEnter }) => {
  const [now, setNow] = React.useState(new Date());
  React.useEffect(()=>{
    const t = setInterval(()=>setNow(new Date()), 60000);
    return ()=>clearInterval(t);
  },[]);
  return (
    <div style={{
      height:'100%', display:'flex', flexDirection:'column',
      background:'radial-gradient(120% 70% at 50% 0%, #1c1f14 0%, #0E0F0C 60%)',
      padding:'8px 28px 24px', position:'relative', overflow:'hidden',
    }}>
      {/* 背景金色装饰 */}
      <svg width="600" height="600" viewBox="0 0 600 600" fill="none"
        style={{position:'absolute', top:-220, left:'50%', transform:'translateX(-50%)', opacity:0.08, pointerEvents:'none'}}>
        <circle cx="300" cy="300" r="180" stroke="var(--gold)" strokeWidth="0.4"/>
        <circle cx="300" cy="300" r="240" stroke="var(--gold)" strokeWidth="0.3"/>
        <circle cx="300" cy="300" r="290" stroke="var(--gold)" strokeWidth="0.2"/>
        <path d="M120 300h360M300 120v360" stroke="var(--gold)" strokeWidth="0.3"/>
      </svg>

      {/* 顶部 logo + 桌号 */}
      <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginTop:8}}>
        <BrandMark size={15}/>
        <div style={{display:'flex',alignItems:'center',gap:6,fontSize:11,
          color:'var(--ink-2)',fontFamily:'var(--mono)',letterSpacing:'0.1em'}}>
          <IconTable size={14} stroke="var(--gold)"/>
          A · 12 号桌
        </div>
      </div>

      {/* 主内容 */}
      <div style={{flex:1,display:'flex',flexDirection:'column',justifyContent:'center',alignItems:'center',textAlign:'center',marginTop:-30}}>
        <div style={{fontSize:11,color:'var(--gold)',letterSpacing:'0.4em',marginBottom:18,fontFamily:'var(--sans)'}}>
          WELCOME · 欢迎光临
        </div>
        <Ornament w={120}/>
        <h1 style={{
          fontFamily:'var(--serif)', fontWeight:400, fontSize:42,
          margin:'24px 0 8px', letterSpacing:'0.2em', color:'var(--ink)',
        }}>
          膳 自 山 野
        </h1>
        <p style={{
          fontSize:13, color:'var(--ink-2)', letterSpacing:'0.18em',
          margin:'0 0 4px', fontFamily:'var(--serif)', fontWeight:300,
        }}>
          食 之 本 真 · 味 之 至 简
        </p>
        <p style={{
          fontSize:10, color:'var(--ink-3)', letterSpacing:'0.3em',
          margin:'10px 0 0', fontFamily:'var(--sans)',
        }}>
          A TASTE OF THE WILDS
        </p>

        {/* 桌位卡片 */}
        <div style={{
          marginTop:48, width:'100%', padding:'18px 22px',
          background:'rgba(255,255,255,0.02)',
          border:'0.5px solid var(--line)', borderRadius:4,
          display:'flex',alignItems:'center',justifyContent:'space-between',
        }}>
          <div style={{textAlign:'left'}}>
            <div style={{fontSize:10,color:'var(--ink-3)',letterSpacing:'0.2em',marginBottom:6}}>YOUR TABLE</div>
            <div style={{fontFamily:'var(--serif)',fontSize:24,color:'var(--ink)',letterSpacing:'0.05em'}}>
              A区 · <span style={{color:'var(--gold)'}}>12</span> 号
            </div>
          </div>
          <div style={{textAlign:'right'}}>
            <div style={{fontSize:10,color:'var(--ink-3)',letterSpacing:'0.2em',marginBottom:6}}>SEATS</div>
            <div style={{fontFamily:'var(--mono)',fontSize:20,color:'var(--ink)'}}>2 / 4</div>
          </div>
        </div>

        <div style={{marginTop:14, fontSize:11, color:'var(--ink-3)', letterSpacing:'0.15em',fontFamily:'var(--mono)'}}>
          {now.getHours().toString().padStart(2,'0')}:{now.getMinutes().toString().padStart(2,'0')} · 服务员 王 已为您服务
        </div>
      </div>

      {/* 底部 CTA */}
      <div>
        <button onClick={onEnter} style={{
          width:'100%', height:54, borderRadius:2,
          background:'var(--gold)', color:'#0E0F0C',
          fontFamily:'var(--serif)', fontWeight:500, fontSize:16,
          letterSpacing:'0.4em', display:'flex',alignItems:'center',justifyContent:'center',gap:14,
        }}>
          开 始 点 单
          <IconChevron size={18} stroke="#0E0F0C" sw={2}/>
        </button>
        <div style={{
          marginTop:14,display:'flex',justifyContent:'center',gap:24,
          fontSize:11,color:'var(--ink-3)',letterSpacing:'0.1em',
        }}>
