                    fontFamily:'var(--mono)',fontSize:9,letterSpacing:'0.2em',
                    color:'var(--ink-3)',
                  }}>{c.sub.toUpperCase()} · {String(dishes.length).padStart(2,'0')}</span>
                </div>
                {/* 菜品列表 */}
                {dishes.map(d=>{
                  const inCart = Object.values(cart).filter(i=>i.dishId===d.id).reduce((s,i)=>s+i.qty,0);
                  return (
                    <div key={d.id} onClick={()=>openDetail(d)} style={{
                      display:'flex', gap:14, padding:'14px 0',
                      borderBottom:'0.5px solid var(--line)', cursor:'pointer',
                    }}>
                      <div style={{position:'relative',flexShrink:0}}>
                        <DishVisual id={d.id} size={86}/>
                        {d.tag && (
                          <div style={{
                            position:'absolute',top:6,left:6,
                            background:'rgba(14,15,12,0.85)',
