                        </div>
                        <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginTop:8}}>
                          <div style={{display:'flex',alignItems:'baseline',gap:10}}>
                            <Price value={d.price}/>
                            <span style={{fontSize:10,color:'var(--ink-3)',fontFamily:'var(--mono)'}}>
                              月售 {d.sold}
                            </span>
                          </div>
                          <div onClick={e=>e.stopPropagation()}>
                            {d.specs && d.specs.length>0 ? (
                              <button onClick={()=>openDetail(d)} style={{
                                padding:'6px 12px',border:'0.5px solid var(--gold)',
                                color:'var(--gold)',fontSize:11,letterSpacing:'0.15em',
                                fontFamily:'var(--serif)',
                              }}>选规格</button>
                            ) : (
                              <Stepper qty={inCart}
                                onInc={()=>addToCart(d, '默认', 0, [])}
