        </div>
        <div style={{flex:1}}>
          {cartCount > 0 ? (
            <>
              <div style={{display:'flex',alignItems:'baseline',gap:6}}>
                <Price value={cartTotal} size={20}/>
                <span style={{fontSize:10,color:'var(--ink-3)',fontFamily:'var(--mono)'}}>另需服务费 ¥4</span>
