// 菜品详情：规格 / 加料 选择
const ScreenDetail = ({ dish, onClose, onConfirm }) => {
  const [qty, setQty] = React.useState(1);
  const [specChoice, setSpecChoice] = React.useState(()=>{
    const init = {};
    (dish.specs||[]).forEach(s => { init[s.k] = s.opts[0]; });
    return init;
  });
  const [addons, setAddons] = React.useState([]); // [{n,p}]

  const specPrice = Object.values(specChoice).reduce((s,o)=>s+(o?o.p:0),0);
  const addonPrice = addons.reduce((s,a)=>s+a.p,0);
  const unitPrice = dish.price + specPrice + addonPrice;

  const toggleAddon = (a) => {
    setAddons(prev => {
      const has = prev.find(x=>x.n===a.n);
      return has ? prev.filter(x=>x.n!==a.n) : [...prev, a];
    });
  };

  const specLabel = Object.values(specChoice).map(o=>o?o.n:'').filter(Boolean).join(' · ');

  return (
    <div style={{
      position:'absolute',inset:0,background:'rgba(0,0,0,0.6)',
      display:'flex',flexDirection:'column',justifyContent:'flex-end',
      animation:'fadeIn 0.2s ease',
    }}>
      <style>{`
        @keyframes fadeIn { from{opacity:0} to{opacity:1} }
        @keyframes slideUp { from{transform:translateY(20px);opacity:0} to{transform:translateY(0);opacity:1} }
      `}</style>
      <div onClick={onClose} style={{flex:1}}/>
      <div style={{
        background:'var(--bg-2)',
        borderTop:'0.5px solid var(--line-2)',
        borderTopLeftRadius:8, borderTopRightRadius:8,
        maxHeight:'88%', display:'flex',flexDirection:'column',
        animation:'slideUp 0.25s cubic-bezier(.2,.8,.2,1)',
      }}>
        {/* 头部图 + 关闭 */}
        <div style={{position:'relative'}}>
          <DishVisual id={dish.id} size={'100%'} label={dish.en}/>
          <div style={{
            position:'absolute',inset:0,
            background:'linear-gradient(180deg,transparent 60%,var(--bg-2) 100%)',
            pointerEvents:'none',
          }}/>
          <button onClick={onClose} style={{
            position:'absolute',top:12,right:12,
            width:32,height:32,borderRadius:'50%',
            background:'rgba(14,15,12,0.7)',backdropFilter:'blur(6px)',
            display:'flex',alignItems:'center',justifyContent:'center',
            border:'0.5px solid var(--line)',
          }}>
            <IconClose size={16} stroke="var(--ink)"/>
          </button>
        </div>

        {/* 内容滚动 */}
        <div className="scroll" style={{flex:1,overflowY:'auto',padding:'0 22px 20px'}}>
          {/* 名称 */}
          <div style={{marginTop:-30,position:'relative'}}>
            <div style={{display:'flex',alignItems:'center',gap:10}}>
              {dish.tag && <Tag>{dish.tag}</Tag>}
              {dish.spicy>0 && <span style={{display:'flex',alignItems:'center'}}><Spicy n={dish.spicy}/></span>}
            </div>
            <h2 style={{
              fontFamily:'var(--serif)',fontSize:24,fontWeight:500,
              color:'var(--ink)',letterSpacing:'0.1em',
              margin:'10px 0 4px',
            }}>{dish.name}</h2>
            <div style={{
              fontSize:10,color:'var(--ink-3)',letterSpacing:'0.25em',fontFamily:'var(--sans)',
            }}>{dish.en.toUpperCase()}</div>
            <div style={{display:'flex',alignItems:'baseline',gap:14,marginTop:14}}>
              <Price value={dish.price} size={22}/>
              <span style={{fontSize:11,color:'var(--ink-3)',fontFamily:'var(--mono)'}}>
                月售 {dish.sold} · ★ 4.8
              </span>
            </div>
            <p style={{
              fontSize:13,color:'var(--ink-2)',lineHeight:1.7,
              marginTop:14,paddingTop:14,borderTop:'0.5px solid var(--line)',
            }}>{dish.desc}。选用当季食材，由主厨现场烹制，建议趁热享用。</p>
          </div>

          {/* 规格 */}
          {(dish.specs||[]).map(s => (
            <div key={s.k} style={{marginTop:24}}>
              <div style={{
                display:'flex',alignItems:'center',gap:8,marginBottom:12,
              }}>
                <span style={{width:3,height:12,background:'var(--gold)'}}/>
                <span style={{
                  fontFamily:'var(--serif)',fontSize:14,letterSpacing:'0.2em',color:'var(--ink)',
                }}>{s.k}</span>
                <span style={{fontSize:9,color:'var(--ink-3)',letterSpacing:'0.2em'}}>必选</span>
              </div>
              <div style={{display:'flex',flexWrap:'wrap',gap:8}}>
                {s.opts.map(o => {
                  const active = specChoice[s.k] && specChoice[s.k].n === o.n;
                  return (
                    <button key={o.n} onClick={()=>setSpecChoice(p=>({...p,[s.k]:o}))} style={{
                      padding:'9px 16px',
                      border: active ? '0.5px solid var(--gold)' : '0.5px solid var(--line-2)',
                      background: active ? 'rgba(201,169,106,0.08)' : 'transparent',
                      color: active ? 'var(--gold)' : 'var(--ink-2)',
                      fontFamily:'var(--serif)', fontSize:13, letterSpacing:'0.1em',
                    }}>
                      {o.n}{o.p>0 && <span style={{fontFamily:'var(--mono)',fontSize:11,marginLeft:6,opacity:0.8}}>+¥{o.p}</span>}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}

          {/* 加料 */}
          {dish.addons && dish.addons.length>0 && (
            <div style={{marginTop:24}}>
              <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:12}}>
                <span style={{width:3,height:12,background:'var(--gold)'}}/>
                <span style={{fontFamily:'var(--serif)',fontSize:14,letterSpacing:'0.2em',color:'var(--ink)'}}>加料</span>
                <span style={{fontSize:9,color:'var(--ink-3)',letterSpacing:'0.2em'}}>可多选</span>
              </div>
              <div style={{display:'flex',flexWrap:'wrap',gap:8}}>
                {dish.addons.map(a => {
                  const active = addons.find(x=>x.n===a.n);
                  return (
                    <button key={a.n} onClick={()=>toggleAddon(a)} style={{
                      padding:'9px 16px',
                      border: active ? '0.5px solid var(--gold)' : '0.5px solid var(--line-2)',
                      background: active ? 'rgba(201,169,106,0.08)' : 'transparent',
                      color: active ? 'var(--gold)' : 'var(--ink-2)',
                      fontFamily:'var(--serif)', fontSize:13, letterSpacing:'0.1em',
                      display:'flex',alignItems:'center',gap:6,
                    }}>
                      {active && <IconCheck size={12} stroke="var(--gold)" sw={2}/>}
                      {a.n}<span style={{fontFamily:'var(--mono)',fontSize:11,opacity:0.85}}>+¥{a.p}</span>
                    </button>
                  );
                })}
              </div>
            </div>
          )}
        </div>

        {/* 底部确认 */}
        <div style={{
          padding:'14px 18px 22px',
          borderTop:'0.5px solid var(--line)',
          background:'var(--bg-2)',
          display:'flex',alignItems:'center',gap:14,
        }}>
          <Stepper qty={qty} onInc={()=>setQty(q=>q+1)} onDec={()=>setQty(q=>Math.max(1,q-1))}/>
          <button onClick={()=>onConfirm(dish, specLabel || '默认', unitPrice, addons, qty)} style={{
            flex:1, height:46,
            background:'var(--gold)',color:'#0E0F0C',
            fontFamily:'var(--serif)',fontSize:14,letterSpacing:'0.25em',
            display:'flex',alignItems:'center',justifyContent:'center',gap:14,
          }}>
            <span>加入购物车</span>
            <Price value={unitPrice*qty} size={14} color="#0E0F0C"/>
          </button>
        </div>
      </div>
    </div>
  );
};
window.ScreenDetail = ScreenDetail;

