            height:46,padding:'0 28px',background:'var(--gold)',color:'#0E0F0C',
            fontFamily:'var(--serif)',fontSize:14,letterSpacing:'0.3em',
            display:'flex',alignItems:'center',gap:10,
          }}>
            提 交 订 单 <IconChevron size={16} stroke="#0E0F0C" sw={2}/>
          </button>
        </div>
      )}
    </div>
  );
};
