};
window.ScreenOrder = ScreenOrder;

// 主 App：路由 + 购物车状态
const { useState, useEffect } = React;

const App = () => {
  const [screen, setScreen] = useState(() => {
    return localStorage.getItem('sy_screen') || 'landing';
  });
  const [cart, setCart] = useState(() => {
    try { return JSON.parse(localStorage.getItem('sy_cart')||'{}'); } catch(e){ return {}; }
  });
  const [detailDish, setDetailDish] = useState(null);
  const [paidTotal, setPaidTotal] = useState(0);

  useEffect(()=>{ localStorage.setItem('sy_screen', screen); }, [screen]);
  useEffect(()=>{ localStorage.setItem('sy_cart', JSON.stringify(cart)); }, [cart]);

  // 添加/调整购物车
  const addToCart = (dish, spec, unitPrice, addons, delta=1, existingKey=null) => {
    const realUnitPrice = unitPrice || dish.price;
    const addonsKey = (addons||[]).map(a=>a.n).sort().join(',');
    const key = existingKey || `${dish.id}|${spec}|${addonsKey}`;
    setCart(prev => {
      const next = {...prev};
      const cur = next[key];
      if (cur) {
        const newQty = cur.qty + delta;
        if (newQty <= 0) delete next[key];
        else next[key] = {...cur, qty: newQty};
      } else if (delta > 0) {
        next[key] = { key, dishId: dish.id, spec, unitPrice: realUnitPrice, addons: addons||[], qty: delta };
      }
      return next;
    });
  };

  const openDetail = (dish) => {
    if (dish.specs && dish.specs.length>0) setDetailDish(dish);
    else addToCart(dish, '默认', dish.price, []);
  };

  const confirmDetail = (dish, spec, unitPrice, addons, qty) => {
    for (let i=0;i<qty;i++) addToCart(dish, spec, unitPrice, addons, 1);
    setDetailDish(null);
  };

  let body;
  if (screen === 'landing') {
    body = <ScreenLanding onEnter={()=>setScreen('menu')}/>;
  } else if (screen === 'menu') {
    body = <ScreenMenu cart={cart} addToCart={addToCart}
              openDetail={openDetail}
              openCart={()=>setScreen('cart')}/>;
  } else if (screen === 'cart') {
    body = <ScreenCart cart={cart} addToCart={addToCart}
              onBack={()=>setScreen('menu')}
              onCheckout={()=>setScreen('checkout')}/>;
  } else if (screen === 'checkout') {
    body = <ScreenCheckout cart={cart}
              onBack={()=>setScreen('cart')}
              onPaid={(t)=>{setPaidTotal(t);setScreen('order');}}/>;
  } else if (screen === 'order') {
    body = <ScreenOrder cart={cart} total={paidTotal||100}
              onBack={()=>{ setCart({}); setScreen('menu'); }}/>;
  }

  return (
    <div style={{
      width:'100%',minHeight:'100vh',
      display:'flex',alignItems:'center',justifyContent:'center',
      padding:'30px 20px',gap:30,
    }}>
      <Phone>
        {body}
        {detailDish && (
          <ScreenDetail dish={detailDish}
            onClose={()=>setDetailDish(null)}
            onConfirm={confirmDetail}/>
        )}
      </Phone>

      {/* 旁注：开发指引 */}
      <div style={{
        position:'fixed',top:24,right:24,
        background:'rgba(22,24,15,0.8)',backdropFilter:'blur(8px)',
        border:'0.5px solid var(--line-2)',
        padding:'14px 16px',maxWidth:230,
        display:window.innerWidth > 900 ? 'block' : 'none',
      }}>
        <div style={{fontFamily:'var(--serif)',fontSize:12,letterSpacing:'0.25em',color:'var(--gold)',marginBottom:10}}>
          原 型 流 程
        </div>
        {[
          ['1','扫码进入'],['2','菜单浏览'],['3','规格详情'],
          ['4','购物车'],['5','结算支付'],['6','订单进度'],
        ].map(([n,k])=>{
          const order = ['landing','menu','menu','cart','checkout','order'];
          const cur = order[parseInt(n)-1] === screen ||
            (n==='3' && detailDish);
          return (
            <div key={n} onClick={()=>{
              const target = ['landing','menu','menu','cart','checkout','order'][parseInt(n)-1];
              setScreen(target);
              setDetailDish(null);
            }} style={{
              display:'flex',alignItems:'center',gap:10,padding:'5px 0',cursor:'pointer',
              color: cur ? 'var(--gold)' : 'var(--ink-2)',
            }}>
              <span style={{fontFamily:'var(--mono)',fontSize:10,opacity:0.6}}>0{n}</span>
              <span style={{fontFamily:'var(--serif)',fontSize:12,letterSpacing:'0.15em'}}>{k}</span>
              {cur && <span style={{flex:1,textAlign:'right',fontSize:9,color:'var(--gold)',letterSpacing:'0.2em'}}>·当前</span>}
            </div>
          );
        })}
        <div style={{height:0.5,background:'var(--line)',margin:'10px 0'}}/>
        <button onClick={()=>{
          setCart({}); setScreen('landing'); setDetailDish(null);
          localStorage.clear();
        }} style={{
          fontSize:10,letterSpacing:'0.2em',color:'var(--ink-3)',
          fontFamily:'var(--serif)',
        }}>↺ 重 置 演 示</button>
      </div>
    </div>
  );
};

ReactDOM.createRoot(document.getElementById('root')).render(<App/>);

content.text:
虚拟文件系统（Virtual File System，VFS）是 AI 设计工具里的核心基础设施之一。下面从原理到实现讲一下。

## 它解决什么问题

浏览器里运行的 AI 设计工具没有真实磁盘访问权限。但又需要：
- 让模型"写文件"、"读文件"、"列目录"
- 跨多轮对话保留用户的项目状态
- 支持多文件项目（HTML + JSX + CSS + 图片）
- 能在 iframe 里"运行"这些文件，像真的在本地服务器一样

所以需要一层**模拟的文件系统**。

## 三种常见实现方式

### 1. 内存 + IndexedDB（浏览器端）

最简单的方式：

```js
// 内存中的文件树
const files = {
  'index.html': { content: '<html>...', mime: 'text/html', mtime: ... },
  'src/app.jsx': { content: 'const App = ...', mime: 'text/jsx', mtime: ... },
  'assets/logo.png': { content: Blob, mime: 'image/png', mtime: ... },
};

// 持久化到 IndexedDB（浏览器原生的大容量 KV 存储）
await db.files.put({ path, content, mtime });
```

- 小文本直接存字符串
- 二进制（图片/字体）存 Blob
- 关闭标签页也不丢

### 2. 后端数据库 + 对象存储（服务端）

生产级方案：
- 文件元数据（路径、大小、修改时间）存 Postgres/MySQL
- 文件内容小的存数据库，大的存 S3/对象存储
- 每个项目一个 `projectId`，文件按路径前缀索引

```
projects/
  abc123/
    index.html
    src/app.jsx
    assets/logo.png
```

好处：多设备同步、协作、版本控制都能做。

### 3. Git 式快照（版本管理）

像 Git 一样把每次修改存成快照：
- 每个文件内容用 hash 去重（同内容只存一份）
- 每次"提交"记录一棵文件树（指向各文件 hash）
- 可以 diff、回滚、分支

## 怎么让 iframe "运行"虚拟文件

这是关键一步。iframe 里的 `<img src="logo.png">` 或 `<script src="app.jsx">` 怎么从虚拟文件系统加载？

### 方法 A：Service Worker 拦截

最优雅。注册一个 Service Worker，拦截 iframe 的所有 `fetch` 请求：

```js
self.addEventListener('fetch', (e) => {
  const path = new URL(e.request.url).pathname;
  const file = await vfs.read(path);
  e.respondWith(new Response(file.content, {
    headers: { 'Content-Type': file.mime }
  }));
});
```

iframe 里写 `<img src="assets/logo.png">` 就能正常加载，完全像真实服务器。

### 方法 B：Blob URL

每个文件生成一个 `blob:` URL：

```js
const url = URL.createObjectURL(new Blob([content], { type: mime }));
// <img src={url}>
```

问题：路径是 `blob:xxx` 而不是 `assets/logo.png`，相对路径不工作。适合简单场景。

### 方法 C：预处理注入

把所有文件打包成一个大 HTML（CSS 内联、图片转 base64、JS 内联），一次性塞给 iframe。像 CodePen 早期那样。简单但不支持多文件引用。

## 模型怎么操作这个文件系统

通过**工具调用**：

```
模型调用: read_file({ path: "index.html" })
  → 返回: "<!doctype html>..."

模型调用: write_file({ path: "src/new.jsx", content: "..." })
  → VFS 写入，通知 iframe 热重载

模型调用: list_files({ path: "src/" })
  → 返回: ["app.jsx", "data.jsx", ...]
```

每个工具就是个普通函数，操作 VFS 的 get/put/list。

## 热重载

文件改了，iframe 自动刷新：
- 监听 VFS 写入事件
- 通过 `postMessage` 通知 iframe
- iframe 内的 loader 重新 import 对应模块（或整体 reload）

复杂一点可以做 HMR（只替换改动的模块，保留 React state）。

## 资源引用

VFS 里还要处理：
- **相对路径解析** — `./foo.jsx` 基于当前文件位置
- **扩展名推断** — `import './app'` 找 `app.jsx` / `app.ts`
- **第三方包** — `import React from 'react'` 重定向到 CDN（unpkg/esm.sh）

## 简化的实现草图

```js
class VFS {
  constructor() {
    this.files = new Map();  // path → { content, mime }
    this.listeners = new Set();
  }

  async read(path) { return this.files.get(path); }

  async write(path, content, mime) {
    this.files.set(path, { content, mime, mtime: Date.now() });
    await idb.put('files', { path, content, mime });
    this.listeners.forEach(fn => fn({ type:'write', path }));
  }

  async list(prefix='') {
    return [...this.files.keys()].filter(p => p.startsWith(prefix));
  }

  onChange(fn) { this.listeners.add(fn); }
}
```

就这么简单。复杂性在边界情况：大文件、并发写、二进制、路径规范化、冲突处理。

## 一句话总结

**虚拟文件系统 = 一个存在内存/数据库里的文件树 + 一套 read/write/list 接口 + 一层让 iframe 能"运行"这些文件的加载机制**。对模型来说它看起来就是普通文件系统；对 iframe 来说它看起来就是普通 HTTP 服务器。中间靠 JS 粘合。

tools.description:
Execute an async JavaScript script to programmatically manipulate project files and images.

Use this when you need to do batch or programmatic operations that would be tedious with individual tool calls — for example:
- Read several files and concatenate or transform them
- Find-and-replace across file contents
- Load an image, get its dimensions, draw on it with Canvas, and save the result
- Compose an image by layering text, shapes, or other images using Canvas
- Generate files programmatically (e.g. build an HTML file from data)

The script runs in an async context with these helpers available:

  log(...args)                      Log output (visible to you in the result)
  await readFile(path)              Read a project file as UTF-8 string
  await readFileBinary(path)        Read a project file as a Blob (for binary data)
  await readImage(path)             Load an image as HTMLImageElement (for canvas drawing)
  await saveFile(path, data)        Save a file. data can be:
                                      - string (saved as text)
                                      - Canvas element (exported as PNG)
                                      - Blob (saved with its MIME type)
  await ls(path?)                   List file names in a directory
  await getCaptures(key)            Retrieve Blob[] stashed by save_screenshot's in_memory_png_key
  createCanvas(width, height)       Create a canvas for drawing

Example — load an image, draw text on it, save:

  const img = await readImage('photo.png');
  const canvas = createCanvas(img.width, img.height);
  const ctx = canvas.getContext('2d');
  ctx.drawImage(img, 0, 0);
  ctx.font = '48px sans-serif';
  ctx.fillStyle = 'white';
  ctx.fillText('Hello!', 50, 100);
  await saveFile('photo-with-text.png', canvas);
  log('Done! Image is ' + img.width + 'x' + img.height);

Example — concatenate files:

  const files = await ls('partials');
  let combined = '';
  for (const f of files) {
    combined += await readFile('partials/' + f) + '\n';
  }
  await saveFile('combined.html', combined);
  log('Combined ' + files.length + ' files');

Do NOT use this for bulk copy of binary files -- it will not work! Use the copy_files tool instead.

Timeout: 30 seconds. Errors are returned to you so you can fix and retry.
